targets.expr:
label_replace(
  (sum by(chain, version, git_commit_hash) (increase(multichain_sign_request_latency_sec_count{environment=~"$environment", step="total", status="in_time"}[30d]))
  / (sum by(chain, version, git_commit_hash) (increase(multichain_sign_request_latency_sec_count{environment=~"$environment", step="total", status="in_time"}[30d]))
    + (sum by(chain, version, git_commit_hash) (increase(multichain_sign_request_delayed{environment=~"$environment"}[30d]))
       or sum by(chain, version, git_commit_hash) (increase(multichain_sign_request_latency_sec_count{environment=~"$environment", step="total", status="in_time"}[30d]) * 0)
      )
    )
  ) * 100,
  "short_hash", "$1...", "git_commit_hash", "(.{6}).*"
)

histogram_quantile(0.95,   
  sum by(le, operation) (  
    rate(multichain_redis_operation_latency_ms_bucket{  
      protocol="triple",  
      environment="$environment",  
      node_account_id=~"$node_account_id"  
    }[$__rate_interval])  
  )  
)

histogram_quantile(0.95,   
  sum by(le, operation) (  
    rate(multichain_redis_operation_latency_ms_bucket{  
      protocol="presignature",  
      environment="$environment",  
      node_account_id=~"$node_account_id"  
    }[$__rate_interval])  
  )  
)
